17	package org.apache.camel.processor.resequencer;
18	
19	import java.util.HashMap;
20	import java.util.Map;
21	import java.util.Timer;
22	import java.util.concurrent.CountDownLatch;
23	import java.util.concurrent.locks.Lock;
24	import java.util.concurrent.locks.ReentrantLock;
25	import java.util.function.Predicate;
26	
27	import org.apache.camel.util.concurrent.ThreadHelper;
28	
29	/**
30	 * Resequences elements based on a given {@link SequenceElementComparator}. This resequencer is designed for
31	 * resequencing element streams. Stream-based resequencing has the advantage that the number of elements to be
32	 * resequenced need not be known in advance. Resequenced elements are delivered via a {@link SequenceSender}.
33	 * <p>
34	 * The resequencer's behaviour for a given comparator is controlled by the <code>timeout</code> property. This is the
35	 * timeout (in milliseconds) for a given element managed by this resequencer. An out-of-sequence element can only be
36	 * marked as <i>ready-for-delivery</i> if it either times out or if it has an immediate predecessor (in that case it is
37	 * in-sequence). If an immediate predecessor of a waiting element arrives the timeout task for the waiting element will
38	 * be cancelled (which marks it as <i>ready-for-delivery</i>).
39	 * <p>
40	 * If the maximum out-of-sequence time difference between elements within a stream is known, the <code>timeout</code>
41	 * value should be set to this value. In this case it is guaranteed that all elements of a stream will be delivered in
42	 * sequence via the {@link SequenceSender}. The lower the <code>timeout</code> value is compared to the out-of-sequence
43	 * time difference between elements within a stream the higher the probability is for out-of-sequence elements delivered
44	 * by this resequencer. Delivery of elements must be explicitly triggered by applications using the {@link #deliver()}
45	 * or {@link #deliverNext()} methods. Only elements that are <i>ready-for-delivery</i> are delivered by these methods.
46	 * The longer an application waits to trigger a delivery the more elements may become <i>ready-for-delivery</i>.
47	 * <p>
48	 * The resequencer remembers the last-delivered element. If an element arrives which is the immediate successor of the
49	 * last-delivered element it is <i>ready-for-delivery</i> immediately. After delivery the last-delivered element is
50	 * adjusted accordingly. If the last-delivered element is <code>null</code> i.e. the resequencer was newly created the
51	 * first arriving element needs <code>timeout</code> milliseconds in any case for becoming <i>ready-for-delivery</i>.
52	 * <p>
53	 */
54	public class ResequencerEngine<E> {
55	
56	    /**
57	     * The element that most recently hash been delivered or <code>null</code> if no element has been delivered yet.
58	     */
59	    private Element<E> lastDelivered;
60	
61	    /**
62	     * Minimum amount of time to wait for out-of-sequence elements.
63	     */
64	    private long timeout;
65	
66	    /**
67	     * A sequence of elements for sorting purposes.
68	     */
69	    private final Sequence<Element<E>> sequence;
70	
71	    /**
72	     * A timer for scheduling timeout notifications.
73	     */
74	    private Timer timer;
75	
76	    /**
77	     * A strategy for sending sequence elements.
78	     */
79	    private SequenceSender<E> sequenceSender;
80	
81	    /**
82	     * Indicates whether an error should be thrown if message older (based on Comparator) than the last delivered
83	     * message is received.
84	     */
85	    private Boolean rejectOld;
86	
87	    /**
88	     * List containing wait conditions to be evaluated whenever the sequence is modified. Access to this field should be
89	     * done inside a lock block.
90	     */
91	    private final Map<CountDownLatch, Predicate<Sequence<?>>> waitConditions = new HashMap<>();
92	
93	    private final Lock lock = new ReentrantLock();
94	
95	    /**
96	     * Creates a new resequencer instance with a default timeout of 2000 milliseconds.
97	     *
98	     * @param comparator a sequence element comparator.
99	     */
100	    public ResequencerEngine(SequenceElementComparator<E> comparator) {
101	        this.sequence = createSequence(comparator);
102	        this.timeout = 2000L;
103	        this.lastDelivered = null;
104	    }
105	
106	    public void start() {
107	        timer = new Timer(
108	                ThreadHelper.resolveThreadName("Camel Thread ${counter} - ${name}", "Stream Resequencer Timer"), true);
109	    }
110	
111	    /**
112	     * Stops this resequencer (i.e. this resequencer's {@link Timer} instance).
113	     */
114	    public void stop() {
115	        timer.cancel();
116	    }
117	
118	    /**
119	     * Returns the number of elements currently maintained by this resequencer.
120	     *
121	     * @return the number of elements currently maintained by this resequencer.
122	     */
123	    public int size() {
124	        lock.lock();
125	        try {
126	            return sequence.size();
127	        } finally {
128	            lock.unlock();
129	        }
130	    }
131	
132	    /**
133	     * Wait for the following condition to happen. Do not call this method while holding a lock on the resequencer
134	     * engine, as it will deadlock. The predicate will be evaluated while holding a lock on the resequencer engine.
135	     *
136	     * @param  pred                 the condition to wait for
137	     * @throws InterruptedException if the thread is interrupted
138	     */
139	    public void waitUntil(Predicate<Sequence<?>> pred) throws InterruptedException {
140	        CountDownLatch latch;
141	        lock.lock();
142	        try {
143	            if (pred.test(sequence)) {
144	                return;
145	            }
146	            latch = new CountDownLatch(1);
147	            waitConditions.put(latch, pred);
148	        } finally {
149	            lock.unlock();
150	        }
151	        latch.await();
152	    }
153	
154	    private void evaluateConditions() {
155	        lock.lock();
156	        try {
157	            for (var it = waitConditions.entrySet().iterator(); it.hasNext();) {
158	                Map.Entry<CountDownLatch, Predicate<Sequence<?>>> e = it.next();
159	                if (e.getValue().test(sequence)) {
160	                    e.getKey().countDown();
161	                    it.remove();
162	                }
163	            }
164	        } finally {
165	            lock.unlock();
166	        }
167	    }
168	
169	    /**
170	     * Returns this resequencer's timeout value.
171	     *
172	     * @return the timeout in milliseconds.
173	     */
174	    public long getTimeout() {
175	        return timeout;
176	    }
177	
178	    /**
179	     * Sets this sequencer's timeout value.
180	     *
181	     * @param timeout the timeout in milliseconds.
182	     */
183	    public void setTimeout(long timeout) {
184	        this.timeout = timeout;
185	    }
186	
187	    public Boolean getRejectOld() {
188	        return rejectOld;
189	    }
190	
191	    public void setRejectOld(Boolean rejectOld) {
192	        this.rejectOld = rejectOld;
193	    }
194	
195	    /**
196	     * Returns the sequence sender.
197	     *
198	     * @return the sequence sender.
199	     */
200	    public SequenceSender<E> getSequenceSender() {
201	        return sequenceSender;
202	    }
203	
204	    /**
205	     * Sets the sequence sender.
206	     *
207	     * @param sequenceSender a sequence element sender.
208	     */
209	    public void setSequenceSender(SequenceSender<E> sequenceSender) {
210	        this.sequenceSender = sequenceSender;
211	    }
212	
213	    /**
214	     * Returns the last delivered element.
215	     *
216	     * @return the last delivered element or <code>null</code> if no delivery has been made yet.
217	     */
218	    E getLastDelivered() {
219	        if (lastDelivered == null) {
220	            return null;
221	        }
222	        return lastDelivered.getObject();
223	    }
224	
225	    /**
226	     * Sets the last delivered element. This is for testing purposes only.
227	     *
228	     * @param o an element.
229	     */
230	    void setLastDelivered(E o) {
231	        lastDelivered = new Element<>(o);
232	    }
233	
234	    /**
235	     * Inserts the given element into this resequencer. If the element is not ready for immediate delivery and has no
236	     * immediate presecessor then it is scheduled for timing out. After being timed out it is ready for delivery.
237	     *
238	     * @param  o                        an element.
239	     * @throws IllegalArgumentException if the element cannot be used with this resequencer engine
240	     */
241	    public void insert(E o) {
242	        lock.lock();
243	        try {
244	            // wrap object into internal element
245	            Element<E> element = new Element<>(o);
246	
247	            // validate the exchange has no problem
248	            if (!sequence.seqComparator().isValid(element)) {
249	                throw new IllegalArgumentException("Element cannot be used in comparator: " + sequence.seqComparator());
250	            }
251	
252	            // validate the exchange shouldn't be 'rejected' (if applicable)
253	            if (rejectOld != null && rejectOld && beforeLastDelivered(element)) {
254	                throw new MessageRejectedException(
255	                        "rejecting message [" + element.getObject()
256	                                                   + "], it should have been sent before the last delivered message ["
257	                                                   + lastDelivered.getObject() + "]");
258	            }
259	
260	            // add element to sequence in proper order
261	            sequence.add(element);
262	
263	            Element<E> successor = sequence.successor(element);
264	
265	            // check if there is an immediate successor and cancel
266	            // timer task (no need to wait any more for timeout)
267	            if (successor != null) {
268	                successor.cancel();
269	            }
270	
271	            // start delivery if current element is successor of last delivered element
272	            if (!successorOfLastDelivered(element) && sequence.predecessor(element) == null) {
273	                element.schedule(defineTimeout());
274	            }
275	
276	            // evaluate wait conditions
277	            evaluateConditions();
278	        } finally {
279	            lock.unlock();
280	        }
281	    }
282	
283	    /**
284	     * Delivers all elements which are currently ready to deliver.
285	     *
286	     * @throws Exception thrown by {@link SequenceSender#sendElement(Object)}.
287	     *
288	     * @see              ResequencerEngine#deliverNext()
289	     */
290	    @SuppressWarnings("StatementWithEmptyBody")
291	    public void deliver() throws Exception {
292	        lock.lock();
293	        try {
294	            while (deliverNext()) {
295	                // do nothing here
296	            }
297	        } finally {
298	            lock.unlock();
299	        }
300	    }
301	
302	    /**
303	     * Attempts to deliver a single element from the head of the resequencer queue (sequence). Only elements which have
304	     * not been scheduled for timing out or which already timed out can be delivered. Elements are delivered via
305	     * {@link SequenceSender#sendElement(Object)}.
306	     *
307	     * @return           <code>true</code> if the element has been delivered <code>false</code> otherwise.
308	     *
309	     * @throws Exception thrown by {@link SequenceSender#sendElement(Object)}.
310	     *
311	     */
312	    public boolean deliverNext() throws Exception {
313	        lock.lock();
314	        try {
315	            if (sequence.isEmpty()) {
316	                return false;
317	            }
318	            // inspect element with the lowest sequence value
319	            Element<E> element = sequence.first();
320	
321	            // if element is scheduled do not deliver and return
322	            if (element.scheduled()) {
323	                return false;
324	            }
325	
326	            // remove deliverable element from sequence
327	            sequence.remove(element);
328	
329	            // set the delivered element to last delivered element
330	            lastDelivered = element;
331	
332	            // deliver the sequence element
333	            sequenceSender.sendElement(element.getObject());
334	
335	            // evaluate wait conditions
336	            evaluateConditions();
337	
338	            // element has been delivered
339	            return true;
340	        } finally {
341	            lock.unlock();
342	        }
343	    }
344	
345	    /**
346	     * Returns <code>true</code> if the given element is the immediate successor of the last delivered element.
347	     *
348	     * @param  element an element.
349	     * @return         <code>true</code> if the given element is the immediate successor of the last delivered element.
350	     */
351	    private boolean successorOfLastDelivered(Element<E> element) {
352	        if (lastDelivered == null) {
353	            return false;
354	        }
355	        if (sequence.seqComparator().successor(element, lastDelivered)) {
356	            return true;
357	        }
358	        return false;
359	    }
360	
361	    /**
362	     * Retuns <code>true</code> if the given element is before the last delivered element.
363	     *
364	     * @param  element an element.
365	     * @return         <code>true</code> if the given element is before the last delivered element.
366	     */
367	    private boolean beforeLastDelivered(Element<E> element) {
368	        if (lastDelivered == null) {
369	            return false;
370	        }
371	        if (sequence.seqComparator().compare(element, lastDelivered) < 0) {
372	            return true;
373	        }
374	        return false;
375	    }
376	
377	    /**
378	     * Creates a timeout task based on the timeout setting of this resequencer.
379	     *
380	     * @return a new timeout task.
381	     */
382	    private Timeout defineTimeout() {
383	        return new Timeout(timer, timeout);
384	    }
385	
386	    private static <E> Sequence<Element<E>> createSequence(SequenceElementComparator<E> comparator) {
387	        return new Sequence<>(new ElementComparator<>(comparator));
388	    }
389	
390	}
