package org.apache.camel.processor.resequencer;

import org.apache.camel.Exchange;
import org.apache.camel.Expression;

/**
 * Reverses the sequence order established by a delegate {@link ExpressionResultComparator}, so that a
 * {@link ResequencerEngine} delivers elements in descending rather than ascending order.
 * <p>
 * A plain pairwise negation of {@link #compare(Exchange, Exchange)} is not sufficient for the stream resequencer:
 * {@link ResequencerEngine} also relies on the {@link #predecessor(Exchange, Exchange)} and
 * {@link #successor(Exchange, Exchange)} relations to detect gaps in the stream and to release elements without
 * waiting for the timeout. Reversing the delivery order therefore swaps what counts as a predecessor and a successor
 * as well, in addition to inverting the comparison.
 */
public class ReverseExpressionResultComparator implements ExpressionResultComparator {

    private final ExpressionResultComparator delegate;

    /**
     * Creates a new comparator that reverses the sequence order of the given <code>delegate</code>.
     *
     * @param delegate the comparator whose ordering is reversed.
     */
    public ReverseExpressionResultComparator(ExpressionResultComparator delegate) {
        this.delegate = delegate;
    }

    @Override
    public void setExpression(Expression expression) {
        delegate.setExpression(expression);
    }

    @Override
    public boolean predecessor(Exchange o1, Exchange o2) {
        return delegate.successor(o1, o2);
    }

    @Override
    public boolean successor(Exchange o1, Exchange o2) {
        return delegate.predecessor(o1, o2);
    }

    @Override
    public int compare(Exchange o1, Exchange o2) {
        return delegate.compare(o2, o1);
    }

    @Override
    public boolean isValid(Exchange o1) {
        return delegate.isValid(o1);
    }

    @Override
    public String toString() {
        return "Reverse[" + delegate + "]";
    }
}

